grammar._cssStyles:
#output {
padding:5rem
}.h1,.h2,.h3,.h4,.h5,.h6,body,h1,h2,h3,h4,h5,h6 {
  font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif
}

.text-normal {
  font-weight:400
}

.h1,.h2,.h3,.h4,.h5,.h6,h1,h2,h3,h4,h5,h6 {
  margin-bottom:1.5rem;
  font-weight:700
}

.h2,h2 {
  font-size:2rem
}

User Agent Style Sheeth2 {
  display:block;
  font-size:1.5em;
  margin-block-start:0.83em;
  margin-block-end:0.83em;
  margin-inline-start:0;
  font-weight:700
}

.margin-top {
  margin-top:1.5rem!important
}

hr {
  height:1px;
  color:#ddd;
  background-color:#ddd;
  border:0
}

code,em,hr,small,strong {
  line-height:1
}

blockquote,caption,dd,dl,fieldset,form,h1,h2,h3,h4,h5,h6,hr,legend,ol,p,pre,table,td,th,ul {
  padding:0;
  margin:0
}

button,hr,input {
  overflow:visible
}

hr,img {
  box-sizing:content-box
}

User Agent Style Sheethr,bdi,output {
  unicode-bidi:isolate
}

User Agent Style Sheethr {
  display:block;
  overflow-x:hidden;
  overflow-y:hidden;
  color:gray;
  margin-block-start:0.5em;
  margin-inline-start:auto;
  border-top-style:inset;
  border-top-width:1px
}

[class~="1/2"],[class~="2/4"],[class~="3/6"],[class~="4/8"],[class~="5/10"],[class~="6/12"] {
  flex-basis:50%;
  width:50%;
  max-width:50%
}

.grid-item {
  padding-right:.75rem;
  padding-left:.75rem
}

.grid {
  display:flex;
  flex:0 1 auto;
  flex-direction:row;
  flex-wrap:wrap;
  margin-right:-.75rem;
  margin-left:-.75rem
}

User Agent Style Sheetaddress,article,aside,details,div,figcaption,figure,footer,header,hgroup,main,menu,nav,search,section,summary {
  display:block
}

*,::after,::before {
  box-sizing:inherit
}

body {
  font-weight:400;
  font-size:1rem;
  line-height:1.5
}

body,small {
  color:#111
}

html {
  font-family:sans-serif;
  -webkit-text-size-adjust:100%
}
